    expect(result.current).toEqual([{
      shotId: 'shot-1',
      shotName: 'Shot 1',
      rowId: 'V1',
      rowIndex: 0,
      start: 0,
      clipIds: ['clip-1'],
      children: [{ clipId: 'clip-1', offset: 0, duration: 2 }],
      color: getShotColor('shot-1'),
      mode: 'video',
    }]);
  });

  it('filters out pinned groups whose trackId does not match any row', () => {
    const rows: TimelineRow[] = [{ id: 'V1', actions: [buildAction('clip-1', 0, 2)] }];
    const { result } = renderHook(() => useShotGroups(
      rows,
      [buildShot('shot-1', 'Shot 1')],
      [buildGroupFromChildren({
        shotId: 'shot-1',
        trackId: 'V2',
        start: 0,
        children: [{ clipId: 'clip-1', offset: 0, duration: 2 }],
        mode: 'images',
      })],
    ));
    expect(result.current).toEqual([]);
  });

  it('trusts normalized children even if the row actions are not hydrated yet', () => {
    const rows: TimelineRow[] = [{ id: 'V1', actions: [] }];
