// ── Types ────────────────────────────────────────────────────────────

export interface ClipOffset {
  clipId: string;
  rowId: string;
  /** Time delta from anchor clip's initial start. */
  deltaTime: number;
  initialStart: number;
  initialEnd: number;
}

export interface PlannedMove {
  kind: 'clip';
  clipId: string;
  sourceRowId: string;
  targetRowId: string;
  newStart: number;
}

export interface PlannedGroupMove {
  kind: 'group';
  groupKey: PinnedGroupKey;
  nextStart: number;
  nextTrackId: string;
}

export type MultiDragMove = PlannedMove | PlannedGroupMove;

export interface MultiDragResult {
  canMove: boolean;
  moves: MultiDragMove[];
}

/** Lightweight rect for rendering secondary ghost indicators. */
export interface GhostRect {
  left: number;
  top: number;
  width: number;
  height: number;
}

const roundConfigValue = (value: number): number => Math.round(value * 100) / 100;

export function updatePinnedShotGroupTrackIdsFromClipTrackMap(
  pinnedShotGroups: TimelineData['config']['pinnedShotGroups'],
  clipTrackMap: Readonly<Record<string, string | undefined>>,
): TimelineData['config']['pinnedShotGroups'] {
  if (!pinnedShotGroups?.length) {
    return pinnedShotGroups;
  }

  let hasChanges = false;
  const nextGroups = pinnedShotGroups.map((group) => {
    const finalTrackIds = new Set(
      group.clipIds
        .map((clipId) => clipTrackMap[clipId])
        .filter((trackId): trackId is string => typeof trackId === 'string' && trackId.length > 0),
    );

    if (finalTrackIds.size !== 1) {
      return group;
    }

    const [nextTrackId] = [...finalTrackIds];
    if (nextTrackId === group.trackId) {
      return group;
    }

    hasChanges = true;
    return buildGroupFromChildren({
      shotId: group.shotId,
      trackId: nextTrackId,
      start: group.start,
      children: group.children,
      mode: group.mode,
      videoAssetKey: group.videoAssetKey,
      imageClipSnapshot: group.imageClipSnapshot,
    }) satisfies PinnedShotGroup;
  });

  return hasChanges ? nextGroups : pinnedShotGroups;
}

export function buildAugmentedData(
  data: TimelineData,
  kind: TrackKind,
  insertAtTop: boolean,
): { augmented: TimelineData; newTrackId: string } | null {
  const augmentedResolvedConfig = addTrack(data.resolvedConfig, kind, insertAtTop ? 0 : undefined);
  const newTrack = augmentedResolvedConfig.tracks.find((track) => {
    return !data.resolvedConfig.tracks.some((existingTrack) => existingTrack.id === track.id);
  });

  if (!newTrack) {
    return null;
  }

  const nextConfig = {
    ...data.config,
    tracks: augmentedResolvedConfig.tracks.map((track) => ({ ...track })),
  };
  const nextRows = insertAtTop
    ? [{ id: newTrack.id, actions: [] }, ...data.rows]
    : [...data.rows, { id: newTrack.id, actions: [] }];

  return {
    augmented: {
      ...data,
      config: nextConfig,
      resolvedConfig: augmentedResolvedConfig,
      rows: nextRows,
      tracks: augmentedResolvedConfig.tracks,
      clipOrder: {
        ...data.clipOrder,
        [newTrack.id]: [],
      },
      signature: getConfigSignature(augmentedResolvedConfig),
      stableSignature: getStableConfigSignature(nextConfig, data.registry),
    },
    newTrackId: newTrack.id,
  };
}

export function buildConfigFromDragResult(
  baseConfig: ResolvedTimelineConfig,
  baseMeta: Record<string, ClipMeta>,
  nextRows: TimelineRow[],
  metaUpdates: Record<string, Partial<ClipMeta>>,
  pinnedShotGroups?: PinnedShotGroup[],
): ResolvedTimelineConfig & { pinnedShotGroups?: PinnedShotGroup[] } {
  const mergedMeta: Record<string, ClipMeta> = Object.fromEntries(
    Object.entries(baseMeta).map(([clipId, clipMeta]) => [
      clipId,
      {
        ...clipMeta,
        ...metaUpdates[clipId],
