      if (typeof clipMeta.hold === 'number') {
        delete nextClip.from;
        delete nextClip.to;
        delete nextClip.speed;
        return [{
          ...nextClip,
          hold: roundConfigValue(position.duration),
        }];
      }

      const speed = clipMeta.speed ?? 1;
      const from = clipMeta.from ?? 0;
