      return [{
        ...nextClip,
        speed: clipMeta.speed,
        from: roundConfigValue(from),
        to: roundConfigValue(getSourceTime({ from, start: position.at, speed }, position.at + position.duration)),
      }];
    }),
    ...(pinnedShotGroups && pinnedShotGroups.length > 0 ? { pinnedShotGroups } : {}),
  };
}

