import { assembleTimelineData, type TimelineData } from '@/tools/video-editor/lib/timeline-data';
import { migrateToFlatTracks, repairConfig } from '@/tools/video-editor/lib/migrate';
import { projectPinnedShotGroups } from '@/tools/video-editor/lib/pinned-group-projection';
import type { TimelineConfig } from '@/tools/video-editor/types';

export function shouldAcceptPolledData(
  editSeq: number,
  savedSeq: number,
  pendingOps: number,
  polledStableSig: string,
  lastSavedStableSig: string,
): boolean {
  if (savedSeq < editSeq) {
    return false;
  }

  if (pendingOps > 0) {
    return false;
  }

  return polledStableSig !== lastSavedStableSig;
}

export function buildDataFromCurrentRegistry(
  config: TimelineConfig,
  current: TimelineData,
): TimelineData {
  // Repair before migration so saved/snapshotted configs keep the canonical shape.
  const migratedConfig = projectPinnedShotGroups(migrateToFlatTracks(repairConfig(config)));
  migratedConfig.tracks = migratedConfig.tracks ?? [];

  const resolvedConfig = {
    output: { ...migratedConfig.output },
    tracks: migratedConfig.tracks,
    clips: migratedConfig.clips.map((clip) => ({
      ...clip,
      assetEntry: clip.asset ? current.resolvedConfig.registry[clip.asset] : undefined,
    })),
    registry: current.resolvedConfig.registry,
  };

  return assembleTimelineData({
    config: migratedConfig,
    configVersion: current.configVersion,
    registry: current.registry,
    resolvedConfig,
    assetMap: Object.fromEntries(
      Object.entries(current.registry.assets ?? {}).map(([assetId, entry]) => [assetId, entry.file]),
    ),
    output: { ...migratedConfig.output },
  });
}

import { getClipTimelineDuration } from '@/tools/video-editor/lib/config-utils';
import type { PinnedShotGroup, TimelineClip, TimelineConfig } from '@/tools/video-editor/types';

const MIN_CHILD_DURATION_SECONDS = 0.05;

export type PinnedGroupKey = Pick<PinnedShotGroup, 'shotId' | 'trackId'>;

type PinnedShotGroupChild = PinnedShotGroup['children'][number];
type PinnedShotGroupExtras = Pick<PinnedShotGroup, 'videoAssetKey' | 'imageClipSnapshot'>;

type BuildGroupFromChildrenArgs = PinnedGroupKey & PinnedShotGroupExtras & {
  start: number;
  children: PinnedShotGroup['children'];
  mode: PinnedShotGroup['mode'];
};

type BuildGroupFromConfigClipsArgs = PinnedGroupKey & PinnedShotGroupExtras & {
  clipIds: string[];
  config: TimelineConfig;
  mode: PinnedShotGroup['mode'];
};

export type CategorizedSelection = {
  freeClipIds: string[];
  groups: Array<{
    groupKey: PinnedGroupKey;
    clipIds: string[];
  }>;
};

const roundTimelineValue = (value: number, digits = 4): number => {
  const factor = 10 ** digits;
  return Math.round(value * factor) / factor;
};

const clampStart = (start: number): number => roundTimelineValue(Math.max(0, start));

const cloneChildren = (children: PinnedShotGroup['children']): PinnedShotGroup['children'] => {
  return children.map((child) => ({
    clipId: child.clipId,
    offset: child.offset,
    duration: child.duration,
  }));
};

const cloneExtras = (extras: PinnedShotGroupExtras): PinnedShotGroupExtras => ({
  videoAssetKey: extras.videoAssetKey,
  imageClipSnapshot: extras.imageClipSnapshot?.map((snapshot) => ({
    ...snapshot,
    meta: { ...snapshot.meta },
  })),
});

const getGroupId = (groupKey: PinnedGroupKey): string => `${groupKey.shotId}:${groupKey.trackId}`;

const isGroupMatch = (group: PinnedShotGroup, groupKey: PinnedGroupKey): boolean => {
  return group.shotId === groupKey.shotId && group.trackId === groupKey.trackId;
};

const getGroupDuration = (children: PinnedShotGroup['children']): number => {
  const lastChild = children[children.length - 1];
  if (!lastChild) {
    return 0;
  }
  return lastChild.offset + lastChild.duration;
};

const setClipTimelineDuration = (
  clip: TimelineClip,
  durationSeconds: number,
): TimelineClip => {
  const nextDuration = roundTimelineValue(Math.max(MIN_CHILD_DURATION_SECONDS, durationSeconds));

  if (typeof clip.hold === 'number' || clip.clipType === 'hold') {
    const nextClip: TimelineClip = { ...clip, hold: nextDuration };
    delete nextClip.from;
    delete nextClip.to;
    delete nextClip.speed;
    return nextClip;
  }

  const nextClip: TimelineClip = { ...clip };
  const speed = clip.speed ?? 1;
  const from = clip.from ?? 0;
  delete nextClip.hold;
  nextClip.from = roundTimelineValue(from);
  nextClip.to = roundTimelineValue(from + (nextDuration * speed));
  nextClip.speed = clip.speed;
  return nextClip;
};

const replaceGroup = (
  config: TimelineConfig,
  groupKey: PinnedGroupKey,
  updater: (group: PinnedShotGroup) => PinnedShotGroup,
): TimelineConfig => {
  if (!config.pinnedShotGroups?.length) {
    return config;
  }

  let hasChanges = false;
  const nextGroups = config.pinnedShotGroups.map((group) => {
    if (!isGroupMatch(group, groupKey)) {
      return group;
    }

    hasChanges = true;
    return updater(group);
  });

  if (!hasChanges) {
    return config;
  }

  return projectPinnedShotGroups({
    ...config,
    pinnedShotGroups: nextGroups,
  });
};

export function normalizeChildren(
  children: PinnedShotGroup['children'],
): PinnedShotGroup['children'] {
  const sortedChildren = cloneChildren(children)
    .filter((child) => child.clipId.length > 0)
    .sort((left, right) => {
      if (left.offset !== right.offset) {
        return left.offset - right.offset;
      }
      return left.clipId.localeCompare(right.clipId);
    });

  let offset = 0;
  return sortedChildren.map((child) => {
    const duration = roundTimelineValue(Math.max(MIN_CHILD_DURATION_SECONDS, child.duration));
    const normalizedChild = {
      clipId: child.clipId,
      offset: roundTimelineValue(offset),
      duration,
    };
    offset += duration;
    return normalizedChild;
  });
}

export function buildGroupFromChildren({
  shotId,
  trackId,
  start,
  children,
  mode,
  ...extras
}: BuildGroupFromChildrenArgs): PinnedShotGroup {
  const normalizedChildren = normalizeChildren(children);

  return {
    shotId,
    trackId,
    start: clampStart(start),
    clipIds: normalizedChildren.map((child) => child.clipId),
    children: normalizedChildren,
    mode,
    ...cloneExtras(extras),
  };
}

export function buildGroupFromConfigClips({
  shotId,
  trackId,
  clipIds,
  config,
  mode,
  ...extras
}: BuildGroupFromConfigClipsArgs): PinnedShotGroup {
  const clipById = new Map(config.clips.map((clip) => [clip.id, clip]));
  const entries = clipIds
    .map((clipId, originalIndex) => {
      const clip = clipById.get(clipId);
      return clip ? { clip, originalIndex } : null;
    })
    .filter((entry): entry is { clip: TimelineClip; originalIndex: number } => entry !== null)
    .sort((left, right) => {
      if (left.clip.at !== right.clip.at) {
        return left.clip.at - right.clip.at;
      }
      return left.originalIndex - right.originalIndex;
    });

  const minStart = entries.length > 0
    ? Math.min(...entries.map((entry) => entry.clip.at))
    : 0;
  const start = clampStart(minStart);
  const children = entries.map(({ clip }) => ({
    clipId: clip.id,
    offset: roundTimelineValue(Math.max(0, clip.at - start)),
    duration: roundTimelineValue(getClipTimelineDuration(clip)),
  }));

  return buildGroupFromChildren({
    shotId,
    trackId,
    start,
    children,
    mode,
    ...extras,
  });
}

export function projectPinnedShotGroups(config: TimelineConfig): TimelineConfig {
  if (!config.pinnedShotGroups?.length) {
    return config;
  }

  const nextGroups = config.pinnedShotGroups.map((group) => buildGroupFromChildren({
    shotId: group.shotId,
    trackId: group.trackId,
    start: group.start,
    children: Array.isArray(group.children) ? group.children : [],
    mode: group.mode,
    videoAssetKey: group.videoAssetKey,

export type PinnedShotGroup = {
  shotId: string;
  trackId: string;
  start: number;
  clipIds: string[];
  children: {
    clipId: string;
    offset: number;
    duration: number;
  }[];
  mode: 'images' | 'video';
  videoAssetKey?: string;
  imageClipSnapshot?: PinnedShotImageClipSnapshot[];
};

export type TimelineConfig = {
  output: TimelineOutput;
  clips: TimelineClip[];
  tracks?: TrackDefinition[];
  customEffects?: Record<string, CustomEffectEntry>;
  pinnedShotGroups?: PinnedShotGroup[];
};

export type AssetRegistryEntry = {
  file: string;
  type?: string;
  duration?: number;
  resolution?: string;
  fps?: number;
  generationId?: string;
  variantId?: string;
  thumbnailUrl?: string;
};

export type AssetRegistry = {
  assets: Record<string, AssetRegistryEntry>;
};

export type ResolvedAssetRegistryEntry = AssetRegistryEntry & {
  src: string;
};

export type ResolvedTimelineClip = TimelineClip & {
  assetEntry?: ResolvedAssetRegistryEntry;
};

export type ResolvedTimelineConfig = {
  output: TimelineOutput;
  tracks: TrackDefinition[];
  clips: ResolvedTimelineClip[];
  registry: Record<string, ResolvedAssetRegistryEntry>;
};

export type TimelineCompositionProps = {
  config?: ResolvedTimelineConfig;
  preview?: boolean;
};

import { describe, expect, it } from 'vitest';
