        { id: 'clip-2', at: 1, track: 'A1', clipType: 'hold', asset: 'asset-2', hold: 2 },
      ],
    };
    const registry: AssetRegistry = {
      assets: {
        'asset-1': { file: 'video.mp4', duration: 3 },
        'asset-2': { file: 'audio.mp3', duration: 2 },
