export function moveGroup(
  config: TimelineConfig,
  groupKey: PinnedGroupKey,
  nextStart: number,
  nextTrackId?: string,
): TimelineConfig {
  return replaceGroup(config, groupKey, (group) => buildGroupFromChildren({
    shotId: group.shotId,
    trackId: nextTrackId ?? group.trackId,
    start: nextStart,
    children: group.children,
    mode: group.mode,
    videoAssetKey: group.videoAssetKey,
    imageClipSnapshot: group.imageClipSnapshot,
  }));
}

export function resizeGroupEdge(
  config: TimelineConfig,
  groupKey: PinnedGroupKey,
  edge: 'left' | 'right',
  deltaSeconds: number,
): TimelineConfig {
  return replaceGroup(config, groupKey, (group) => {
    const currentDuration = getGroupDuration(group.children);
    if (currentDuration <= 0 || group.children.length === 0) {
      return buildGroupFromChildren({
        shotId: group.shotId,
        trackId: group.trackId,
        start: group.start,
        children: group.children,
        mode: group.mode,
        videoAssetKey: group.videoAssetKey,
        imageClipSnapshot: group.imageClipSnapshot,
      });
    }

    const minimumDuration = group.children.length * MIN_CHILD_DURATION_SECONDS;
    let nextStart = group.start;
    let nextDuration = currentDuration;

    if (edge === 'right') {
      nextDuration = Math.max(minimumDuration, currentDuration + deltaSeconds);
    } else {
      const currentEnd = group.start + currentDuration;
      const maxStart = currentEnd - minimumDuration;
      nextStart = Math.max(0, Math.min(group.start + deltaSeconds, maxStart));
      nextDuration = Math.max(minimumDuration, currentEnd - nextStart);
    }

    const scale = nextDuration / currentDuration;
    const scaledChildren = group.children.map((child) => ({
      clipId: child.clipId,
      offset: roundTimelineValue(child.offset * scale),
      duration: roundTimelineValue(child.duration * scale),
    }));

    return buildGroupFromChildren({
      shotId: group.shotId,
      trackId: group.trackId,
      start: nextStart,
      children: scaledChildren,
      mode: group.mode,
      videoAssetKey: group.videoAssetKey,
      imageClipSnapshot: group.imageClipSnapshot,
    });
  });
}

export function replaceGroupChildren(
  config: TimelineConfig,
  groupKey: PinnedGroupKey,
  nextChildren: PinnedShotGroup['children'],
): TimelineConfig {
  return replaceGroup(config, groupKey, (group) => buildGroupFromChildren({
    shotId: group.shotId,
    trackId: group.trackId,
    start: group.start,
    children: nextChildren,
    mode: group.mode,
    videoAssetKey: group.videoAssetKey,
    imageClipSnapshot: group.imageClipSnapshot,
  }));
}

export function findEnclosingPinnedGroup(
  config: TimelineConfig,
  clipId: string,
): { group: PinnedShotGroup; groupKey: PinnedGroupKey; index: number } | null {
  const groups = config.pinnedShotGroups ?? [];
  const index = groups.findIndex((group) => group.clipIds.includes(clipId));
  if (index < 0) {
    return null;
  }

  const group = groups[index];
  return {
    group,
    groupKey: {
      shotId: group.shotId,
      trackId: group.trackId,
    },
    index,
  };
}

